// ============================================================
// ⚙️  CONFIG — Edit all technical settings here
// For system prompt → edit the [System Prompt] node instead
// ============================================================

return [{
  json: {
    ...($input.first()?.json ?? {}),
    _config: {
      // MCP Server
      // mcp_url: "http://172.16.13.170:8000/mcp",
      mcp_url: "http://host.docker.internal:8000/mcp",
      // LLM Provider: "ollama" | "claude"
      llm_provider: "ollama",
      // Ollama settings
      ollama_url: "http://172.16.15.59:11434/api/chat",
      ollama_model: "gemma4:31b-cloud",
    }
  }
}];

const suite = $json;
return suite.cases.map(tc => ({
  json: {
    test_suite_id: suite.test_suite_id,
    ...tc
  }
}));

const tc = $json;
const steps = tc.steps || [];

return steps.map((s, idx) => ({
  json: {
    test_suite_id: tc.test_suite_id,
    test_case_id: tc.test_case_id,
    test_case_name: tc.test_case_name,
    test_data: tc.test_data || {},
    step_index: idx + 1,
    total_steps: steps.length,
    test_step_id: s.test_step_id,
    test_step_description: String(s.test_step_description || '').trim()
  },
  pairedItem: { item: 0 }
}));

const elements = $json.result?.elements ?? [];
const stepData  = $('Test Step').item.json;
const step      = stepData.test_step_description ?? '';
const sessionId = `session_${$execution.id}_${stepData.test_suite_id}`;
const testData  = stepData.test_data ?? {};

let attempt = 1, retryCtx = null;
try {
  const pr = $('Prep Retry').item.json;
  if (pr?.attempt) { attempt = pr.attempt; retryCtx = pr.retry_context; }
} catch(e) {}

// ── Compact element format — jauh lebih hemat token ──────────────
const MAX_EL = 50;
const elLines = elements.slice(0, MAX_EL).map((el, i) => {
  const parts = [
    `[${i}]`,
    el.tag,
    el.id        ? `id="${el.id}"`               : null,
    el.name      ? `name="${el.name}"`            : null,
    el.type      ? `type="${el.type}"`            : null,
    el.aria_label? `aria-label="${el.aria_label}"`  : null,
    el.placeholder?`placeholder="${el.placeholder}"`: null,
    el.disabled  ? `DISABLED`                    : null,
    el.text      ? `"${el.text.slice(0,60)}"`    : null,
    el.suggested_selector ? `→ ${el.suggested_selector}` : null,
  ].filter(Boolean);
  return parts.join(' ');
});
const elStr = elLines.join('\n');
// ─────────────────────────────────────────────────────────────────
const finalPrompt = [
  $('System Prompt').item.json.system_prompt,
  `SESSION ID: ${sessionId}`,
  `AVAILABLE ELEMENTS (${elements.length} total, showing ${elLines.length}):\n${elStr}`,
  Object.keys(testData).length > 0 ? `TEST DATA:\n${JSON.stringify(testData)}` : null,
  `STEP: "${step}"`,
].filter(Boolean).join('\n\n');

console.log('=== PROMPT DEBUG ===');
console.log('system_prompt chars:', $('System Prompt').item.json.system_prompt?.length);
console.log('elements str chars:', elStr.length);
console.log('total prompt chars:', finalPrompt.length);
console.log('====================');

return [{ json: { prompt: finalPrompt } }];

return [{
  json: {
    prompt: [
      $('System Prompt').item.json.system_prompt,
      `SESSION ID: ${sessionId}`,
      `AVAILABLE ELEMENTS (${elements.length} total, showing ${elLines.length}):\n${elStr}`,
      Object.keys(testData).length > 0
        ? `TEST DATA:\n${JSON.stringify(testData)}`
        : null,
      retryCtx
        ? `⚠️ RETRY ${attempt}/3 — FAILED: ${retryCtx.error}\nDo NOT repeat same index. Pick different element.`
        : null,
      `STEP: "${step}"`,
      `Output JSON only.`
    ].filter(Boolean).join('\n\n')
  }
}];

const raw = $json.response
         ?? $json.message?.content
         ?? $json.content?.[0]?.text
         ?? $json.data
         ?? "";

const looksLikeError = !raw || raw.trim().length < 5 ||
  /^(callback|undefined|null|error|TypeError|ReferenceError|SyntaxError)/i.test(raw.trim());

const cleaned = raw
  .replace(/<think>[\s\S]*?<\/think>/gi, '')
  .trim()
  .replace(/^```(?:json)?\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

const looksLikeJSON = cleaned.startsWith('{') || cleaned.startsWith('[');

const _attempt = (() => {
  try { return $('Prep Retry').item.json?.attempt ?? 1; } catch(e) { return 1; }
})();

if (looksLikeError || !looksLikeJSON) {
  const stepData = $('Test Step').item.json;
  return [{
    json: {
      _llm_error: true,
      _attempt,
      _raw_response: String(raw).slice(0, 200),
      method: "noop",
      params: {},
      meta: {
        test_suite_id:         stepData.test_suite_id,
        test_case_id:          stepData.test_case_id,
        test_case_name:        stepData.test_case_name,
        step_index:            stepData.step_index,
        total_steps:           stepData.total_steps,
        test_step_id:          stepData.test_step_id,
        test_step_description: stepData.test_step_description
      }
    }
  }];
}

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('LLM returned invalid JSON: ' + raw.slice(0, 300));
}

if (!parsed.method && parsed.action) {
  parsed.method = parsed.action;
}

if (!parsed.method) {
  if (parsed.value !== undefined && (parsed.field || parsed.target || parsed.selector)) {
    parsed.method = "fill";
  } else if (parsed.url) {
    parsed.method = "navigate";
  } else if (parsed.target || parsed.selector || parsed.field) {
    parsed.method = "click";
  }
}

if (parsed.method && !parsed.params) {
  parsed.params = {
    selector: parsed.selector || parsed.target || parsed.field || "",
    text: parsed.text || parsed.value || "",
    url: parsed.url || ""
  };
}

if (!parsed.method) {
  throw new Error('LLM JSON missing method field. Raw: ' + raw.slice(0, 300));
}

const stepData = $('Test Step').item.json;
return [{
  json: {
    ...parsed,
    _attempt,
    meta: {
      test_suite_id:         stepData.test_suite_id,
      test_case_id:          stepData.test_case_id,
      test_case_name:        stepData.test_case_name,
      step_index:            stepData.step_index,
      total_steps:           stepData.total_steps,
      test_step_id:          stepData.test_step_id,
      test_step_description: stepData.test_step_description
    }
  }
}];

const html = $json.executed?.content ?? "";

if (!html || typeof html !== "string") {
  return [{
    json: {
      ok: $json.ok ?? false,
      meta: $json.meta ?? null,
      llm_command: $json.llm_command ?? null,
      title: $json.title ?? null,
      plain_text: null,
      plain_text_len: 0,
      snippet: null,
      csv_saved: $json.executed?.csv_saved ?? null,
      message: $json.executed?.message ?? null
    }
  }];
}

const title = (html.match(/<title>([\s\S]*?)<\/title>/i)?.[1] ?? "").trim() || ($json.title ?? null);

function extractMain(h) {
  const m1 = h.match(/<div[^>]*id="xwikicontent"[^>]*>([\s\S]*?)<\/div>\s*<\/div>\s*<\/main>/i);
  if (m1?.[1]) return m1[1];
  const m2 = h.match(/<main[^>]*>([\s\S]*?)<\/main>/i);
  if (m2?.[1]) return m2[1];
  return h;
}

let mainHtml = extractMain(html)
  .replace(/<script[\s\S]*?<\/script>/gi, " ")
  .replace(/<style[\s\S]*?<\/style>/gi, " ")
  .replace(/<noscript[\s\S]*?<\/noscript>/gi, " ");

let text = mainHtml
  .replace(/<br\s*\/?>/gi, "\n")
  .replace(/<\/p>/gi, "\n")
  .replace(/<\/li>/gi, "\n")
  .replace(/<[^>]+>/g, " ")
  .replace(/&nbsp;/g, " ").replace(/&amp;/g, "&")
  .replace(/&lt;/g, "<").replace(/&gt;/g, ">")
  .replace(/&quot;/g, '"').replace(/&#39;/g, "'")
  .replace(/[ \t]+\n/g, "\n")
  .replace(/\n{3,}/g, "\n\n")
  .replace(/[ \t]{2,}/g, " ")
  .trim();

return [{
  json: {
    ...$json,
    title,
    plain_text: text,
    plain_text_len: text.length,
    snippet: text.slice(0, 500),
    csv_saved: $json.executed?.csv_saved ?? null,
    message: $json.executed?.message ?? null
  }
}];

