// Output the complete flat body for POST /mcp (ExecuteRequest format)
const meta = $json.meta || {};
const attempt = $json._attempt ?? 1;
const final_attempt = attempt >= 3;

const sessionId = `session_${$execution.id}_${meta.test_suite_id}`;

const params = { ...($json.params || {}) };
delete params.sessionId;

return [{
  json: {
    sessionId: sessionId,
    method: $json.method,
    params: params,
    test_suite_id: meta.test_suite_id,
    test_case_id: meta.test_case_id,
    test_case_name: meta.test_case_name,
    step_index:  meta.step_index,
    total_steps: meta.total_steps,
    test_step_id: meta.test_step_id,
    test_step_description: meta.test_step_description,
    step_started_at: new Date().toISOString(),
    final_attempt: final_attempt,
    expected_result: meta.test_step_description,
  }
}];

const item = $input.first().json;

let attempt = 1;
try {
  const pr = $('Prep Retry').item.json;
  if (pr?.attempt) attempt = pr.attempt;
} catch(e) {
  // Code Prep Retry hasn't run yet — this is attempt 1
  attempt = 1;
}

return [{
  json: {
    ...item,
    _attempt:   attempt,
    _can_retry: attempt < 3   // max 3 total attempts
  }
}];

const item   = $input.first().json;   // Code "Check Retry" output
const step   = $('Test Step').item.json;

return [{
  json: {
    // Fields needed by Get Browser Interactables session ID
    test_suite_id:         step.test_suite_id,
    test_case_id:          step.test_case_id,
    test_case_name:        step.test_case_name,
    test_data:             step.test_data ?? {},
    step_index:            step.step_index,
    total_steps:           step.total_steps,
    test_step_id:          step.test_step_id,
    test_step_description: step.test_step_description,

    // Retry state
    attempt:       item._attempt + 1,
    retry_context: {
      previous_command: item.llm_command ?? null,
      error:            item.error       ?? null,
      error_type:       item.error_type  ?? null,
    }
  }
}];
